- (void)featureView:(WBHomeVappFeatureView *)view didToggleType:(WBHomeVappFeatureType)type {
    UIView *p = view;
    UICollectionViewCell *targetCell = nil;
    while (p) {
        if ([p isKindOfClass:UICollectionViewCell.class]) { targetCell = (UICollectionViewCell *)p; break; }
        p = p.superview;
    }
    NSIndexPath *indexPath = targetCell ? [self.collectionView indexPathForCell:targetCell] : nil;
    if (!indexPath) return;
    WBVAppModel *vapp = self.dualvapps[indexPath.row];
    switch (type) {
            // 更多功能
        case WBHomeVappFeatureTypeMoreFunctions: {
            WBSettingGlobalViewController *settingGlobalVC = [[WBSettingGlobalViewController alloc] init];
            settingGlobalVC.settingVapp = vapp;
            [self.navigationController pushViewController:settingGlobalVC animated:YES];
            break;
        }
            // 消息推送
        case WBHomeVappFeatureTypeNotifications: {
            [[WBBenefitManager sharedManager] toggleNotificationForVapp:vapp
                                                              presenter:self
                                                              setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 安全锁
        case WBHomeVappFeatureTypeLock: {
            [[WBBenefitManager sharedManager] toggleLockForVapp:vapp
                                                      presenter:self
                                                     switchCell:nil
                                                      setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 图标伪装
        case WBHomeVappFeatureTypeDisguise: {
            [[WBBenefitManager sharedManager] toggleDisguiseForVapp:vapp
                                                          presenter:self
                                                         switchCell:nil
                                                          setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 全局伪装
        case WBHomeVappFeatureTypePretense: {
            [[WBBenefitManager sharedManager] togglePretenseForVapp:vapp
                                                          presenter:self
                                                          setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 一键启动
        case WBHomeVappFeatureTypeOneclick: {
            [[WBBenefitManager sharedManager] toggleOneclickForVapp:vapp
                                                          presenter:self
                                                          setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
    }
}

