        UICollectionViewCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:reuseIdentifier_add forIndexPath:indexPath];

        UIImageView *customImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"Home_addVapp_button"]];
        customImageView.frame = CGRectMake(20, 15, ZOOM(24), ZOOM(24));
        customImageView.center = CGPointMake(cell.contentView.bounds.size.width/2, ZOOM(18));
        [cell.contentView addSubview:customImageView];
        cell.backgroundColor = RGB(246, 246, 246);
        cell.layer.cornerRadius = ZOOM(12);

        return cell;
    } else {//vapp
        WBVAppModel *vapp = self.dualvapps[indexPath.row];
        WBVappCollectionViewCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:reuseIdentifier forIndexPath:indexPath];
        cell.vapp = vapp;
        cell.delegate = self;
        cell.parentVC = self;
        if (!cell.vapp.isDownload || WBSettingManager.sharedManager.HideVIPPrivilege) {
            for (WBHomeVappFeatureView *view in cell.selectedFeatureViews) {
                view.hidden = YES;
            }
            cell.hideFeaturesButton.hidden = YES;
            cell.editFeaturesButton.hidden = YES;
            cell.vappBackView.backgroundColor = [UIColor clearColor];
            cell.backgroundColor = [UIColor clearColor];
        } else {
            for (WBHomeVappFeatureView *view in cell.selectedFeatureViews) {
                view.hidden = NO;
            }
            cell.hideFeaturesButton.hidden = NO;
            cell.editFeaturesButton.hidden = NO;
            cell.vappBackView.backgroundColor = [UIColor whiteColor];
            cell.backgroundColor = RGB(246, 246, 246);
        }
        cell.moreButton.hidden = !cell.vapp.isDownload;
        return cell;
    }
}

- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout sizeForItemAtIndexPath:(NSIndexPath *)indexPath {
    if (indexPath.row == self.dualvapps.count) { // 加号按钮单元格
        return CGSizeMake(ZOOM(355), ZOOM(36));
    }
    return CGSizeMake(ZOOM(355), ZOOM(216));
}


#pragma mark - WBHomeVappFeatureViewDelegate

// vapp功能开关事件
- (void)featureView:(WBHomeVappFeatureView *)view didToggleType:(WBHomeVappFeatureType)type {
    UIView *p = view;
    UICollectionViewCell *targetCell = nil;
    while (p) {
        if ([p isKindOfClass:UICollectionViewCell.class]) { targetCell = (UICollectionViewCell *)p; break; }
        p = p.superview;
    }
    NSIndexPath *indexPath = targetCell ? [self.collectionView indexPathForCell:targetCell] : nil;
    if (!indexPath) return;
    WBVAppModel *vapp = self.dualvapps[indexPath.row];
    switch (type) {
            // 更多功能
        case WBHomeVappFeatureTypeMoreFunctions: {
            WBSettingGlobalViewController *settingGlobalVC = [[WBSettingGlobalViewController alloc] init];
            settingGlobalVC.settingVapp = vapp;
            [self.navigationController pushViewController:settingGlobalVC animated:YES];
            break;
        }
            // 消息推送
        case WBHomeVappFeatureTypeNotifications: {
            [[WBBenefitManager sharedManager] toggleNotificationForVapp:vapp
                                                              presenter:self
                                                              setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 安全锁
        case WBHomeVappFeatureTypeLock: {
            [[WBBenefitManager sharedManager] toggleLockForVapp:vapp
                                                      presenter:self
                                                     switchCell:nil
                                                      setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 图标伪装
        case WBHomeVappFeatureTypeDisguise: {
            [[WBBenefitManager sharedManager] toggleDisguiseForVapp:vapp
                                                          presenter:self
                                                         switchCell:nil
                                                          setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 全局伪装
        case WBHomeVappFeatureTypePretense: {
            [[WBBenefitManager sharedManager] togglePretenseForVapp:vapp
                                                          presenter:self
                                                          setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
            // 一键启动
        case WBHomeVappFeatureTypeOneclick: {
            [[WBBenefitManager sharedManager] toggleOneclickForVapp:vapp
                                                          presenter:self
                                                          setSwitch:^(BOOL on, BOOL animated) {
                if (view.switchButton) [view.switchButton setOn:on animated:animated];
            }];
            break;
        }
    }
}

