payload.aggregated_output:
        self.vappNameLabel.text = [_vapp literalStatus];
    } else {
        self.vappNameLabel.text = [_vapp getDisplayName];
    }
    self.vappIconImageView.imageURL = [_vapp getDisplayIconURL];

    if ((_vapp.status & (WBVappStatusResourceWaitingDownload | WBVappStatusResourceDownloading | WBVappStatusResourceDownloaded | WBVappStatusResourceDownloadError | WBVappStatusResourceDownloadInterrupted | WBVappStatusResourceDownloadGiveUp | WBVappStatusResourceInstalling | WBVappStatusResourceInstalled | WBVappStatusResourceInstallError | WBVappStatusIniting)) || _vapp.status == WBVappStatusNone) {
        self.progressView.hidden = YES;
    } else {
        self.progressView.hidden = NO;
        if (_vapp.progress == 1.0f) {
            switch (_vapp.status) {
                case WBVappStatusDownloading:
                case WBVappStatusDownloaded:
                    self.progressView.progress = 0.999f;
                    break;
                default:
                    self.progressView.progress = _vapp.progress;
                    break;
            }
        } else if (_vapp.progress == 0.0f) {
            switch (_vapp.status) {
                case WBVappStatusWaitingDownload:
                case WBVappStatusDownloading:
                case WBVappStatusWaitingInstall:
                case WBVappStatusInstalling:
                    self.progressView.progress = 0.001f;
                    break;
                default:
                    self.progressView.progress = _vapp.progress;
                    break;
            }
        } else {
            self.progressView.progress = _vapp.progress;
        }
    }

    if (_vapp.featureStatusInfo) {
        for (WBHomeVappFeatureView *view in self.selectedFeatureViews) {
            if (!view.switchButton) continue;
            switch (view.featureType) {
                case WBHomeVappFeatureTypeNotifications:
                    [view.switchButton setOn:_vapp.featureStatusInfo.isNotificationSwitchOn];
                    break;
                case WBHomeVappFeatureTypeLock:
                    [view.switchButton setOn:_vapp.featureStatusInfo.isLockSwitchOn];
                    break;
                case WBHomeVappFeatureTypeDisguise:
                    [view.switchButton setOn:_vapp.featureStatusInfo.isDisguiseSwitchOn];
                    break;
                case WBHomeVappFeatureTypePretense:
                    [view.switchButton setOn:_vapp.featureStatusInfo.isPretenseSwitchOn];
                    break;
                case WBHomeVappFeatureTypeOneclick:
                    [view.switchButton setOn:_vapp.featureStatusInfo.isOneClickSwitchOn];
                    break;
                default:
                    break;
            }
        }
    }

    NSString *keyId = [self selectedFeaturesKeyId];
    NSUInteger mask = [WBSettingManager.sharedManager selectedFeaturesMaskForBundleId:keyId];
    if (mask == 0) {
        mask = WBSelectedFeatureMaskNotification;
    }
    NSUInteger benefit = WBSettingManager.sharedManager.Benefit;
    NSUInteger supportedMask = 0;
    if (benefit & WBUserBenefitNotification) supportedMask |= WBSelectedFeatureMaskNotification;
    if (benefit & WBUserBenefitLock)         supportedMask |= WBSelectedFeatureMaskLock;
    if (benefit & WBUserBenefitPretense)     supportedMask |= WBSelectedFeatureMaskPretense;
    if (benefit & WBUserBenefitDisguise)     supportedMask |= WBSelectedFeatureMaskDisguise;
    if (benefit & WBUserBenefitOneClick)     supportedMask |= WBSelectedFeatureMaskOneClick;
    NSUInteger sanitizedMask = mask & supportedMask;
    if (sanitizedMask != mask) {
        [WBSettingManager.sharedManager setSelectedFeaturesMask:sanitizedMask forBundleId:keyId];
    }
    NSArray<NSString *> *savedOrderedCodes = [WBSettingManager.sharedManager selectedFeatureCodesForBundleId:keyId];
    NSArray<NSString *> *orderedCodes = [self sanitizeCodes:savedOrderedCodes withSupportedMask:supportedMask];
    if (orderedCodes.count == 0) {
        orderedCodes = [self codesFromMask:sanitizedMask];
    }
    [WBSettingManager.sharedManager setSelectedFeatureCodes:orderedCodes forBundleId:keyId];
    if (_vapp.isDownload || !WBSettingManager.sharedManager.HideVIPPrivilege) {
        self.selectedFeatureCodes = orderedCodes;
    } else {
        self.selectedFeatureCodes = @[];
    }
}


