- (void)hideFeatures {
    if (!WBSettingManager.sharedManager.IsVIP && !WBSettingManager.sharedManager.IsSVIP) {
        [WBHomeViewController showVIPOnlyFeatureBottomPopup:@"homeHideFeatures"];
        return;
    }

    if (!WBSettingManager.sharedManager.NeverShowHideFeaturesAlert) {
        NSString *message = @"如需再次开启功能栏，请至【我的】-【设置】中点击「显示会员权益」";
        WBPopupDisposableViewController *popup = [[WBPopupDisposableViewController alloc] initWithTitle:@"温馨提示" message:message cancel:@"关闭" confirm:@"确认隐藏" confirmAction:^(BOOL confirmed, BOOL neverShowAgain) {
            if (confirmed) {
                for (WBHomeVappFeatureView *view in self.selectedFeatureViews) {
                    view.hidden = YES;
                }
                self.hideFeaturesButton.hidden = YES;
                self.editFeaturesButton.hidden = YES;
                self.backgroundColor = [UIColor clearColor];
                self.vappBackView.backgroundColor = [UIColor clearColor];
                WBSettingManager.sharedManager.HideVIPPrivilege = TRUE;
                WBSettingManager.sharedManager.NeverShowHideFeaturesAlert = neverShowAgain;
                PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
            }
        }];
        popup.modalPresentationStyle = UIModalPresentationOverFullScreen;
        popup.modalTransitionStyle = UIModalTransitionStyleCrossDissolve;
        UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
        [rootVC presentViewController:popup animated:NO completion:nil];
    } else {
        for (WBHomeVappFeatureView *view in self.selectedFeatureViews) {
            view.hidden = YES;
        }
        self.hideFeaturesButton.hidden = YES;
        self.editFeaturesButton.hidden = YES;
        self.backgroundColor = [UIColor clearColor];
        self.vappBackView.backgroundColor = [UIColor clearColor];
        WBSettingManager.sharedManager.HideVIPPrivilege = TRUE;
        PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
    }
}

- (void)editFeatures {
    if (!WBSettingManager.sharedManager.IsVIP && !WBSettingManager.sharedManager.IsSVIP) {
        [WBHomeViewController showVIPOnlyFeatureBottomPopup:@"homeEditFeatures"];
        return;
    }

    WBEditFeaturesViewController *editFeaturesVC = [WBEditFeaturesViewController new];
    editFeaturesVC.titleLabel.text = @"编辑权益";
    editFeaturesVC.delegate = self;
    NSString *keyId = [self selectedFeaturesKeyId];
    NSUInteger mask = [WBSettingManager.sharedManager selectedFeaturesMaskForBundleId:keyId];
    if (mask == 0) mask = WBSelectedFeatureMaskNotification;
    NSUInteger benefit = WBSettingManager.sharedManager.Benefit;
    NSUInteger supportedMask = 0;
    if (benefit & WBUserBenefitNotification) supportedMask |= WBSelectedFeatureMaskNotification;
    if (benefit & WBUserBenefitLock)         supportedMask |= WBSelectedFeatureMaskLock;
    if (benefit & WBUserBenefitPretense)     supportedMask |= WBSelectedFeatureMaskPretense;
    if (benefit & WBUserBenefitDisguise)     supportedMask |= WBSelectedFeatureMaskDisguise;
    if (benefit & WBUserBenefitOneClick)     supportedMask |= WBSelectedFeatureMaskOneClick;
    NSUInteger sanitizedMask = mask & supportedMask;
    if (sanitizedMask != mask) {
        [WBSettingManager.sharedManager setSelectedFeaturesMask:sanitizedMask forBundleId:keyId];
    }
    NSArray<NSString *> *savedOrderedCodes = [WBSettingManager.sharedManager selectedFeatureCodesForBundleId:keyId];
    NSArray<NSString *> *orderedCodes = [self sanitizeCodes:savedOrderedCodes withSupportedMask:supportedMask];
    if (orderedCodes.count == 0) {
        orderedCodes = [self codesFromMask:sanitizedMask];
    }
    [WBSettingManager.sharedManager setSelectedFeatureCodes:orderedCodes forBundleId:keyId];
    editFeaturesVC.initialSelectedCodes = orderedCodes;
    [editFeaturesVC show];
}

