- (NSArray<WBVAppModel *> *)vapps {

    return WBVAppManager.sharedManager.myApps;
}


- (instancetype)init {

    [[NSNotificationCenter defaultCenter] addObserverForName:WBTapVappNotificationInNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
        WBVAppModel *tempVApp = nil;
        NSString *vappBundleId = [notification.userInfo objectForKey:@"vappBundleId"];

        for (WBVAppModel *vapp in self.vapps) {
            if ([vapp.bundleId isEqualToString:vappBundleId]) {
                tempVApp = vapp;
                break;
            }
        }

        if (!tempVApp) {
            return;
        }

        [self onPressVApp:tempVApp isFromVappNotification:YES];
    }];
    [[NSNotificationCenter defaultCenter] addObserverForName:WBHomePromoAlertTimeEndNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
        self.alertPromo = nil;
        [self updateAllConstraints];
    }];
    [[NSNotificationCenter defaultCenter] addObserverForName:WBHomePromoAlertTimeRefreshNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
        [self loadPromoAlert];
    }];
    [[NSNotificationCenter defaultCenter] addObserverForName:WBUserMsgStatusUpdateNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
        [self handleNewMsgFromFeedbacks];
    }];

    self.bannerAdHeight = ZOOM(75);
