    self.nativeAdRetryCount = 0;

    UICollectionViewFlowLayout *flowLayout = [[UICollectionViewFlowLayout alloc] init];
    flowLayout.minimumInteritemSpacing = ZOOM(5);
    flowLayout.minimumLineSpacing = ZOOM(8);
    flowLayout.sectionInset = UIEdgeInsetsMake(ZOOM(16), ZOOM(10), ZOOM(8), ZOOM(10));
    return [super initWithCollectionViewLayout:flowLayout];

}

- (void)viewDidLoad {
    [super viewDidLoad];

    // 添加VIP订阅按钮/客服按钮
    self.navigationItem.leftBarButtonItem = self.vipBarButtonItem;
    self.navigationItem.rightBarButtonItem = self.defaultReadFeedbackBarButtonItem;

    [self loadPromoAlert];
    [self loadBannerData];
    [self loadDualVapp];
    self.collectionView.backgroundColor = [UIColor whiteColor];
    [self.collectionView registerClass:[WBVappCollectionViewCell class] forCellWithReuseIdentifier:reuseIdentifier];
    self.collectionView.alwaysBounceVertical = YES;
    [self.collectionView registerClass:[UICollectionViewCell class] forCellWithReuseIdentifier:reuseIdentifier_add];
    [self.collectionView registerClass:UICollectionReusableView.class forSupplementaryViewOfKind:UICollectionElementKindSectionHeader withReuseIdentifier:reuseIdentifier_banner];
    self.collectionView.alwaysBounceVertical = YES;
    self.collectionView.showsVerticalScrollIndicator = NO;
    self.collectionView.showsHorizontalScrollIndicator = NO;
    self.collectionView.allowsSelection = NO;
    [self.collectionView addSubview:self.purchaseButton];
    if (self.alertPromo) {
        [self.collectionView addSubview:self.promoCountDownView];
    }

    UITapGestureRecognizer *tap = [[UITapGestureRecognizer alloc] init];
    tap.cancelsTouchesInView = NO;
    tap.delegate = self;
    [tap addTarget:self action:@selector(gestureDetected:)];
    [self.collectionView addGestureRecognizer:tap];
    UILongPressGestureRecognizer *longpress = [[UILongPressGestureRecognizer alloc] init];
    longpress.minimumPressDuration = 0.3;
    longpress.delegate = self;
    [longpress addTarget:self action:@selector(gestureDetected:)];
    [self.collectionView addGestureRecognizer:longpress];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleMyVAppClick:) name:WBAddPageClickMyVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppGet:) name:WBGetVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppReserve:) name:WBReserveVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppDownloadError:) name:WBVAppDownloadErrorNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppInstallError:) name:WBVAppInstallErrorNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(customPopupDismissed:) name:CustomPopupDismissedNotification object:nil];  // 接收活动弹窗的通知，将 vapp 的启动状态设置为FALSE。
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleForceRedownloadNotification:) name:WBForceRedownloadVappNotification object:nil];

    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypePageHomeShow defaultHandler:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handlePopupDismiss) name:WBPopupDismissNotification object:nil];

//	[self addShortcutButtonToNavigationBar];

    [self.view addSubview:self.toAdAwardsVCButton];
}


