    [super viewWillAppear:animated];
    [self.collectionView reloadData];
    [WBEventManager logAppPageShowEvent:@"Home" from:@""];
    // Nav back from passwordvc or other conditions, which indicates password auth failed or other conditions that cause vapp fail to launch.
    [self handleNewMsgFromFeedbacks];

    if (self.isVappLaunching) {
        self.vappLaunching = false; // Reset launch status.
    }

    if ([WBSettingManager sharedManager].bannerAdEnableShow && ([WBSettingManager sharedManager].bannerAdPosition & WBAdsShowPositionHomePage)) {
        [self groMoreBannerAdLoad]; // 加载banner广告
