    if ([WBSettingManager sharedManager].nativeAdEnableShow && ([WBSettingManager sharedManager].nativeAdPosition & WBAdsShowPositionHomePage)) {
        [self groMoreNativeAdLoad]; // 加载信息流广告
    }

    if (![WBSettingManager sharedManager].rewardAdEnableShow) {
        self.toAdAwardsVCButton.hidden = YES;
    } else {
        self.toAdAwardsVCButton.hidden = NO;
    }
}

