    if (count <= 0) {
        self.hideFeaturesButton.hidden = YES;
        self.editFeaturesButton.hidden = YES;
        self.backgroundColor = [UIColor clearColor];
        self.vappBackView.backgroundColor = [UIColor clearColor];
        return;
    }

    self.hideFeaturesButton.hidden = NO;
    self.editFeaturesButton.hidden = NO;
    self.backgroundColor = RGB(246, 246, 246);
    self.vappBackView.backgroundColor = [UIColor whiteColor];

    CGFloat itemHeight = (count == 3) ? ZOOM(52) : ZOOM(78);
    WBHomeVappFeatureView *prev = nil;

    for (NSUInteger i = 0; i < count; i++) {
        NSString *code = self.selectedFeatureCodes[i];
        WBHomeVappFeatureView *view = [self featureViewForCode:code];
        view.compact = (count == 3);
        view.delegate = self.parentVC;
        if (count == 1) {
            view.cornerStyle = WBHomeVappFeatureCornerStyleTop;
        } else if (count == 2) {
            view.cornerStyle = (i == 0) ? WBHomeVappFeatureCornerStyleTop : WBHomeVappFeatureCornerStyleBottom;
        } else {
            view.cornerStyle = (i == 0) ? WBHomeVappFeatureCornerStyleTop : ((i == count - 1) ? WBHomeVappFeatureCornerStyleBottom : WBHomeVappFeatureCornerStyleMiddle);
        }
        [self.contentView addSubview:view];
        [self.selectedFeatureViews addObject:view];

        [view mas_makeConstraints:^(MASConstraintMaker *make) {
            make.left.equalTo(self.vappBackView.mas_right).offset(ZOOM(8));
            make.right.equalTo(self.contentView).offset(ZOOM(-8));
            make.height.mas_equalTo(itemHeight);
            if (prev) {
                make.top.equalTo(prev.mas_bottom);
            } else {
                make.top.equalTo(self.contentView).offset(ZOOM(8));
            }
        }];
        prev = view;
        view.seperatorLine.hidden = (i == count - 1);
        if (view.switchButton) {
            if ([code isEqualToString:@"notification"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isNotificationSwitchOn];
            } else if ([code isEqualToString:@"lock"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isLockSwitchOn];
            } else if ([code isEqualToString:@"disguise"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isDisguiseSwitchOn];
            } else if ([code isEqualToString:@"pretense"]) {
                [view.switchButton setOn:_vapp.featureStatusInfo.isPretenseSwitchOn];
