    [self.editFeaturesButton mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.hideFeaturesButton.mas_right).offset(ZOOM(8));
        make.top.equalTo(self.hideFeaturesButton);
        make.right.equalTo(self.contentView).offset(ZOOM(-8));
        make.height.mas_equalTo(ZOOM(36));
