                                       forVApp:_downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:[NSString stringWithFormat:@"response code error %zd", resp.statusCode] timeCost:timeCost];
        return;
    }
    if (location == nil) {
        NSLog(@"Resource download: unknown download error occur");
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
