@interface WBVAppDownloadManager() <NSURLSessionDownloadDelegate>

@property(strong, nonatomic) NSMutableArray<WBVAppModel *> *downloadQueue;

@property(weak, nonatomic) NSURLSessionDownloadTask *downloadTask;
@property(strong, nonatomic) WBVAppModel *downloadingVApp;
@property(strong, nonatomic) NSURLSession *session;
@property(assign, nonatomic) CFAbsoluteTime downloadStartTime;

