+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBVAppResDownloadManager alloc] init];
    });
    return instance;
}

- (instancetype)init {
    if (self = [super init]) {
        _downloadQueue = [NSMutableArray array];
        _downloadCompletionHandler = [NSMutableDictionary dictionary];
        [self doTimelyCheck];
        _session = [NSURLSession sessionWithConfiguration:NSURLSessionConfiguration.defaultSessionConfiguration delegate:self delegateQueue:[NSOperationQueue mainQueue]];
        // 注册监听器
        [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleDeleteNotification:) name:WBDeleteDownloadResCancelNotification object:nil];
    }
    return self;
}

- (void)dealloc {
    // 取消注册监听器
    [[NSNotificationCenter defaultCenter] removeObserver:self name:WBDeleteDownloadResCancelNotification object:nil];
}

- (BOOL)isDownloading {
    if (_downloadTask && _downloadingVApp) {
        return TRUE;
    }
    return FALSE;
}


- (void)onEnterBackground {
    // if background mode's not enabled and the task's resumable, then save the task
}

- (void)onAppWillTerminate {
    if ([self isDownloading]) {
        // try to save the task
        [self cancelDownloadingTaskByProducingResumeData];
    }
}

- (void)doTimelyCheck {
    dispatch_after(dispatch_time_delay(1.0), dispatch_get_main_queue(), ^{
        [self checkDownloadQueue];
    });
}

- (void)checkDownloadQueue {
    if (_downloadTask == nil) {
        if ([_downloadQueue count] > 0) {
            if (!_downloadingVApp) {
                _downloadingVApp = _downloadQueue.firstObject;
                [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceWaitingDownload forVApp:_downloadingVApp];
                _downloadingVApp.progress = 0.0f;
                _tryCount = 0;
            }

            switch (_downloadingVApp.status) {

                case WBVappStatusResourceWaitingDownload:
                    if (_tryCount >= 3) {
                        [self handleDownloadGiveUp];
                    } else {
//                        _downloadingVApp.versionInfo.resURL = @"http://127.0.0.1/testError.bin";
                        _downloadTask = [_session downloadTaskWithURL:[NSURL URLWithString:_downloadingVApp.versionInfo.resURL]];
                        [_downloadTask resume];
                        _downloadStartTime = CFAbsoluteTimeGetCurrent();
                        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloading forVApp:_downloadingVApp];
                        [WBEventManager logVappResDownloadEvent:_downloadingVApp];
                    }
                    break;

                case WBVappStatusResourceDownloaded: {
                    [_downloadQueue popFirstObject];
                    void (^downloadCompletionHandler)(void) = self.downloadCompletionHandler[_downloadingVApp.bundleId];
                    if (downloadCompletionHandler) {
                        downloadCompletionHandler();
                        [self.downloadCompletionHandler removeObjectForKey:_downloadingVApp.bundleId];
                    }
                    [[WBStorageManager sharedManager] unzipRes:_downloadingVApp];
                    _downloadingVApp = nil;
                    break;
                }

                case WBVappStatusResourceDownloadError:
                    @synchronized (self) {
                        _tryCount += 1;
                    }
                    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceWaitingDownload forVApp:_downloadingVApp];
                    _downloadingVApp.progress = 0.0f;
                    break;

                case WBVappStatusResourceDownloadInterrupted: {
                    if (_tryCount >= 3) {
                        [self handleDownloadGiveUp];
                        break;
                    }
                    if (UIApplication.sharedApplication.applicationState == UIApplicationStateActive) {
                        NSData *resumeData = [WBStorageManager.sharedManager loadResumableDataForURL:_downloadingVApp.versionInfo.resURL];
                        if (resumeData) {
                            if (!_downloadStartTime) {
                                _downloadStartTime = CFAbsoluteTimeGetCurrent();
                            }
                            _downloadTask = [_session downloadTaskWithResumeData:resumeData];
                            [_downloadTask resume];
                            NSLog(@"Resource download: resume");
                            [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloading forVApp:_downloadingVApp];
                        } else {
                            [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
                            [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                                         errorDomain:WBErrorDomainResDownload
                                                          errorCode:10001
                                                       errorMessage:@"Download interrupted and cannot be resumed due to missing resume data"
                                                           forVApp:_downloadingVApp];
                        }
                    }
                    break;
                }
                default:
                    break;
            }
        }
    }
    [self doTimelyCheck];
}

- (void)handleDownloadGiveUp {
    [_downloadQueue removeObject:_downloadingVApp];
    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadGiveUp
                                    forVApp:_downloadingVApp];
    NSString *bundleId = _downloadingVApp.bundleId;
    void (^completionHandler)(void) = self.downloadCompletionHandler[bundleId];
    if (completionHandler) {
        completionHandler();
        [self.downloadCompletionHandler removeObjectForKey:bundleId];
    }
    if (_downloadTask) {
        [_downloadTask cancel];
        _downloadTask = nil;
    }
    _downloadStartTime = 0;
    _downloadingVApp = nil;
    _tryCount = 0;
    NSLog(@"Resource download: too many retries, give up");
}

- (void)setVAppDownloadPriorityInQueue:(WBVAppModel *)vapp index:(unsigned int)index {
    NSParameterAssert([_downloadQueue containsObject:vapp]);
    if (index == 0) {
        if ([_downloadingVApp isEqual:vapp]) return;
        if (_downloadTask) {
            NSParameterAssert(_downloadingVApp && _downloadingVApp == _downloadQueue.firstObject);
            [self cancelDownloadingTaskByProducingResumeData];
            [_downloadQueue removeFirstObject];
            [_downloadQueue addObject:_downloadingVApp];
            _downloadingVApp = nil;
        }
        return;
    }
    [_downloadQueue removeObject:vapp];
    [_downloadQueue insertObject:vapp atIndex:index];
}


- (BOOL)addToDownloadQueue:(WBVAppModel *)vapp {
    [_downloadQueue addObject:vapp];
    [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceWaitingDownload forVApp:vapp];
    vapp.progress = 0.0f;
    return TRUE;
}


